-- =============================================================================
-- MERL Dashboard - Migration 0019: Indicator remarks / reference notes
-- =============================================================================
-- Attaches curated narrative remarks (progress comments and what remains to be
-- done, from the source GEF PIR) to each VCAP2 indicator, and adds Indicator 14
-- (policies and sector reviews). Remarks are kept for reference and persist in
-- merl.project_profiles independent of the source document.
-- =============================================================================

BEGIN;

UPDATE merl.project_profiles
SET data = jsonb_set(data, '{indicators}', '[{"code": "Indicator 11", "description": "# direct project beneficiaries (individuals, gender-disaggregated)", "unit": "people", "baseline": "0", "midterm": "4,000", "end": "307,150 (entire population)", "status": "exceeded", "baseline_val": 0, "midterm_val": 4000, "end_val": 307150, "history": [{"period": "30 Jun 2025", "value": 4000, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 6684, "note": "3rd PIR (FY26): M 3,382 / F 3,302"}], "remarks": "Achieved 6,684 direct beneficiaries (M 3,382 / F 3,302), surpassing the mid-term target of 4,000. 483 participants trained during the reporting period.", "current": "3rd PIR (FY26): M 3,382 / F 3,302", "current_val": 6684, "progress_pct": 2}, {"code": "Core Indicator 1.1", "description": "Terrestrial protected areas newly created (ha)", "unit": "ha", "baseline": "0", "midterm": "1,000 ha", "end": "2,298 ha", "status": "exceeded", "baseline_val": 0, "midterm_val": 1000, "end_val": 2298, "history": [{"period": "30 Jun 2025", "value": 1000, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 3757, "note": "3rd PIR (FY26): 12,546 ha mapped"}], "remarks": "12,546 ha mapped across 5 fully consented CCAs (Mataloi 2,903 ha, Wusi 2,414 ha, Linduri 1,343 ha, Valapei 2,325 ha, Vasalea 3,560 ha). 3,757 ha formally established (Wusi + Linduri under the Environment Protection Act) - the end-of-project target of 2,298 ha is already exceeded. 13 new letters of consent secured.", "current": "3rd PIR (FY26): 12,546 ha mapped", "current_val": 3757, "progress_pct": 163}, {"code": "Core Indicator 1.2", "description": "Terrestrial protected areas under improved management effectiveness (ha)", "unit": "ha", "baseline": "0", "midterm": "5,000 ha", "end": "11,215 ha", "status": "on_track", "baseline_val": 0, "midterm_val": 5000, "end_val": 11215, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 8099, "note": "3rd PIR (FY26): 3 CCAs completed"}], "remarks": "METT assessments commenced for 8 CCAs (13,129 ha) and completed for 3 (Tabwemasana/Kerepua, Vatthe, Quanlap = 8,099 ha); Quanlap METT score rose 28 to 41. Remaining: finalise METT validations (Vatthe, Mataloi, Tasmate) and launch Vasalea, Mataloi, Losiro and Lonwolwol management plans. SESA/ESIA/ESMP completed and disclosed.", "current": "3rd PIR (FY26): 3 CCAs completed", "current_val": 8099, "progress_pct": 72}, {"code": "Indicator 10", "description": "# investments in climate-proofing of public conveyance, water provision and evacuation infrastructure", "unit": "investments", "baseline": "0", "midterm": "15", "end": "25", "status": "on_track", "baseline_val": 0, "midterm_val": 15, "end_val": 25, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 13, "note": "3rd PIR (FY26): 13 investments completed"}], "remarks": "13 investments completed - incl. Wusi water supply, 10 Drinking Water Safety & Security Plans (West Coast Santo), a plumbers training workshop in Wusi (27 participants, 3 women) and 1 of 7 climate-proofed Area Council buildings. Water systems and further AC offices under procurement/construction (South Epi, Futuna, South Maewo, South Tanna, Torres).", "current": "3rd PIR (FY26): 13 investments completed", "current_val": 13, "progress_pct": 52}, {"code": "Indicator 12", "description": "% targeted V-CAP communities receiving timely, accurate early warnings of coastal hazards", "unit": "%", "baseline": "0", "midterm": "10%", "end": "100%", "status": "in_progress", "baseline_val": 0, "midterm_val": 10, "end_val": 100, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 0, "note": "3rd PIR (FY26): infrastructure under construction"}], "remarks": "0% attributable to this project so far, though an estimated 60% of communities already receive early warnings via SMS initiated under VCAP1. VMGD Weather TV Room launched 10 Dec. Under construction: Luganville early-warning centre, VMGD TV weather station, VMGD laboratory refurbishment, and 6 automatic weather stations + 6 river gauges (expected end 2025).", "current": "3rd PIR (FY26): infrastructure under construction", "current_val": 0, "progress_pct": 0}, {"code": "Indicator 13", "description": "# climate change adaptation plans developed and integrated into Area Council Development Plans", "unit": "plans", "baseline": "0", "midterm": "10", "end": "20", "status": "on_track", "baseline_val": 0, "midterm_val": 10, "end_val": 20, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 3, "note": "3rd PIR (FY26): 3 CCAPs completed (South Epi)"}], "remarks": "3 CCAPs completed for South Epi Area Council (Nulnesa, Tamale, Nalema); 5 more ready for director signature (Linduri, Sauriki, Pareo, Tasmate, Vasalea). 23 CCAP workshops held; consultations in South Epi (Shefa), Torres, Vanua-Lava and Mota (Torba). 7 additional CCAPs expected by end 2025.", "current": "3rd PIR (FY26): 3 CCAPs completed (South Epi)", "current_val": 3, "progress_pct": 15}, {"code": "Indicator 14", "description": "# policies and sector reviews developed incorporating biodiversity conservation, SLM and LDN", "unit": "policies", "baseline": "0", "midterm": "1", "end": "3", "status": "on_track", "baseline_val": 0, "midterm_val": 1, "end_val": 3, "history": [{"period": "30 Jun 2025", "value": 0, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 1, "note": "3rd PIR (FY26): DoCC Strategic Plan launched"}], "remarks": "1 completed: DoCC Strategic Plan (launched Feb 2025). In progress: Climate Change Act review (at drafting stage with State Law Office, regulatory impact analysis done), Agriculture policy, and Environment Protection & Conservation Act review (with ECARE, pending Parliament Sept 2026). Meteorology & Geohazards Acts pending new department structures. Vanuatu National Vulnerability Assessment Framework completed.", "current": "3rd PIR (FY26): DoCC Strategic Plan launched", "current_val": 1, "progress_pct": 33}, {"code": "Indicator 15", "description": "# people trained at local, provincial and national level (gender-disaggregated)", "unit": "people", "baseline": "0", "midterm": "500 (F 250)", "end": "2,000 (F 1,000)", "status": "on_track", "baseline_val": 0, "midterm_val": 500, "end_val": 2000, "history": [{"period": "30 Jun 2025", "value": 250, "note": "2nd PIR (FY25)"}, {"period": "30 Jun 2026", "value": 627, "note": "3rd PIR (FY26): M 414 / F 213"}], "remarks": "627 participants trained (M 414 / F 213), surpassing the mid-term target of 500. Trainings included the CCA Planning Workshop (2024), DWSSP workshops (Narovorovo, South Maewo, Port Quimi), the BIORAP inception workshop (40 stakeholders) and an SLM planning workshop.", "current": "3rd PIR (FY26): M 414 / F 213", "current_val": 627, "progress_pct": 31}]'::jsonb),
    updated_at = now()
WHERE code = 'VCAP2';

COMMIT;
